css:
.undertaking-page {
    font-family: "Helvetica", Arial, sans-serif;
    font-size: 16px;
    color: #000;
    padding: 30px 40px 20px 40px;
    line-height: 1.7;
}

.top-right {
    text-align: right;
    font-weight: 700;
    font-size: 18px;
    margin-bottom: 10px;
}

.title-main {
    text-align: center;
    font-weight: 700;
    font-size: 22px;
    margin-top: 10px;
    margin-bottom: 35px;
    text-transform: uppercase;
}

.title-sub {
    text-align: center;
    font-weight: 700;
    font-size: 20px;
    margin-bottom: 55px;
    text-transform: uppercase;
}

.paragraph {
    text-align: justify;
    font-size: 17px;
    margin-bottom: 28px;
}

.inline-field {
    display: inline-block;
    border-bottom: 1px dotted #000;
    min-height: 18px;
    vertical-align: bottom;
    padding: 0 4px 2px 4px;
    line-height: 1.2;
}

.w-name {
    min-width: 330px;
}

.w-programme {
    min-width: 180px;
}

.w-year {
    min-width: 90px;
}

.w-cid {
    min-width: 220px;
}

.bottom-section {
    margin-top: 90px;
}

.stamp-box {
    width: 110px;
    height: 90px;
    border: 1px solid #000;
    text-align: center;
    font-size: 18px;
    line-height: 1.3;
    padding-top: 10px;
    margin-bottom: 90px;
}

.signature-row {
    width: 100%;
    margin-top: 40px;
}

.signature-block {
    width: 45%;
    display: inline-block;
    vertical-align: top;
    text-align: center;
}

.signature-block.right {
    float: right;
}

.signature-title {
    font-weight: 700;
    font-size: 18px;
    margin-bottom: 8px;
}

.signature-label {
    font-size: 17px;
}

.clearfix::after {
    content: "";
    display: block;
    clear: both;
}

@media print {
    .undertaking-page {
        padding: 20px 30px;
    }
}
